#include <omp.h>
#include "common.h"

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

extern int omp_num_threads;

static void lud_diagonal_omp(float *m, int matrix_dim, int offset) {
    int i, j;
    float shadow[BLOCK_SIZE][BLOCK_SIZE];
    int array_offset = offset * matrix_dim + offset;

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            shadow[i][j] = m[array_offset + j];
        }
        array_offset += matrix_dim;
    }

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        for (int tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i; j++) {
                shadow[tx][i] -= shadow[tx][j] * shadow[j][i];
            }
            shadow[tx][i] /= shadow[i][i];
        }

        for (int tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i + 1; j++) {
                shadow[i + 1][tx] -= shadow[i + 1][j] * shadow[j][tx];
            }
        }
    }

    array_offset = (offset + 1) * matrix_dim + offset;
    for (i = 1; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[array_offset + j] = shadow[i][j];
        }
        array_offset += matrix_dim;
    }
}

static void lud_perimeter_omp(float *m, int matrix_dim, int offset, int block_id) {
    float dia[BLOCK_SIZE][BLOCK_SIZE];
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];
    int i, j;
    int array_offset;

    array_offset = offset * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            dia[i][j] = m[array_offset + j];
        }
        array_offset += matrix_dim;
    }

    array_offset = offset * matrix_dim + offset + (block_id + 1) * BLOCK_SIZE;
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            peri_row[i][j] = m[array_offset + j];
        }
        array_offset += matrix_dim;
    }

    array_offset = (offset + (block_id + 1) * BLOCK_SIZE) * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            peri_col[i][j] = m[array_offset + j];
        }
        array_offset += matrix_dim;
    }

    for (j = 0; j < BLOCK_SIZE; j++) {
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (int k = 0; k < i; k++) {
                peri_row[i][j] -= dia[i][k] * peri_row[k][j];
            }
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            for (int k = 0; k < j; k++) {
                peri_col[i][j] -= peri_col[i][k] * dia[k][j];
            }
            peri_col[i][j] /= dia[j][j];
        }
    }

    array_offset = (offset + 1) * matrix_dim + offset + (block_id + 1) * BLOCK_SIZE;
    for (i = 1; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[array_offset + j] = peri_row[i][j];
        }
        array_offset += matrix_dim;
    }

    array_offset = (offset + (block_id + 1) * BLOCK_SIZE) * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[array_offset + j] = peri_col[i][j];
        }
        array_offset += matrix_dim;
    }
}

static void lud_internal_omp(float *m, int matrix_dim, int offset, int bx, int by) {
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];

    int global_row_id = offset + (by + 1) * BLOCK_SIZE;
    int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            peri_row[ty][tx] = m[(offset + ty) * matrix_dim + global_col_id + tx];
            peri_col[ty][tx] = m[(global_row_id + ty) * matrix_dim + offset + tx];
        }
    }

    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            float sum = 0.0f;
            for (int i = 0; i < BLOCK_SIZE; i++) {
                sum += peri_col[ty][i] * peri_row[i][tx];
            }
            m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
        }
    }
}

void lud_omp(float *m, int matrix_dim) {
    int offset = 0;

    for (offset = 0; offset < matrix_dim - BLOCK_SIZE; offset += BLOCK_SIZE) {
        lud_diagonal_omp(m, matrix_dim, offset);

        int blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;

#pragma omp parallel for num_threads(omp_num_threads) schedule(static)
        for (int b = 0; b < blocks; b++) {
            lud_perimeter_omp(m, matrix_dim, offset, b);
        }

#pragma omp parallel for collapse(2) num_threads(omp_num_threads) schedule(static)
        for (int by = 0; by < blocks; by++) {
            for (int bx = 0; bx < blocks; bx++) {
                lud_internal_omp(m, matrix_dim, offset, bx, by);
            }
        }
    }

    lud_diagonal_omp(m, matrix_dim, offset);
}
